#[derive(Debug)]
pub struct GeneralizedLinearMixedModelFit {
    /// Fixed effects coefficients
    pub fixed_effects: Array1<f64>,
    /// Random effects covariance matrices
    pub random_covariance: HashMap<String, Array2<f64>>,
    /// Predicted random effects (EBLUPs)
    pub random_effects_pred: HashMap<String, Array2<f64>>,
    /// Log-likelihood at convergence
    pub log_likelihood: f64,
    /// Number of iterations to convergence
    pub iterations: usize,
    /// Fitted values on response scale
    pub fitted_values: Array1<f64>,
