use stats_models::{Fit, Lm};
use std::collections::HashMap;
use std::env;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = env::args().collect();

    if args.len() < 4 {
        eprintln!("Usage: oracle_runner <test_type> <data_file> <output_file> [formula]");
        std::process::exit(1);
    }

    let test_type = &args[1];
    let data_file = &args[2];
    let output_file = &args[3];
    let formula = args.get(4).map(|s| s.as_str()).unwrap_or("y ~ x");

    match test_type.as_str() {
        "lm" => run_lm_test(data_file, output_file, formula),
        _ => {
            eprintln!("Unknown test type: {}", test_type);
            std::process::exit(1);
        }
    }
}

fn run_lm_test(
    data_file: &str,
    output_file: &str,
    _formula: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    // Read CSV data
    let mut data = HashMap::new();
    let mut rdr = csv::Reader::from_path(data_file)?;

    // Get headers
    let headers = rdr.headers()?.clone();
    for header in headers.iter() {
        data.insert(header.to_string(), Vec::new());
    }

    // Read data
    for result in rdr.records() {
        let record = result?;
        for (i, field) in record.iter().enumerate() {
            let header = &headers[i];
            let value: f64 = field.parse()?;
            data.get_mut(header).unwrap().push(value);
        }
    }

    // Extract response and predictors based on formula
    // For now, assume simple "y ~ x" format
    let response_data = data.get("y").ok_or("Response variable 'y' not found")?;
    let predictor_data = data.get("x").ok_or("Predictor variable 'x' not found")?;

    // Create design matrix (intercept + x)
    let n = response_data.len();
    let mut design_matrix = Vec::with_capacity(n * 2);

    for &value in predictor_data.iter() {
        design_matrix.push(1.0); // intercept
        design_matrix.push(value); // x
    }

    // Fit linear model using the direct fit method
    let fit_result = Lm::fit(&design_matrix, response_data, n, 2)?;

    // Prepare output in format expected by comparator
    let mut wtr = csv::Writer::from_path(output_file)?;
    wtr.write_record(["metric", "value", "index"])?;

    // Write coefficients using the Fit trait
    for (i, coeff) in fit_result.coefficients().iter().enumerate() {
        wtr.write_record(["coefficients", &coeff.to_string(), &(i + 1).to_string()])?;
    }

    wtr.flush()?;
    Ok(())
}

