//!
//! These tests ensure numerical accuracy matches or exceeds lme4
//! for various mixed effects model scenarios.

use approx::assert_relative_eq;
use mixed_models::{LinearMixedModel, MixedModelSpec, RandomEffectsSpec};
use ndarray::{Array1, Array2};
use std::collections::HashMap;

/// Test a simple random intercept model: y ~ x + (1|group)
/// This corresponds to lme4::lmer(y ~ x + (1|group), data)
#[test]
fn test_random_intercept_vs_lme4() {
    // Generate test data matching R oracle test setup
    let n_obs = 100;
    let n_groups = 10;
    let obs_per_group = n_obs / n_groups;

    // Fixed effects design matrix (intercept + x)
    let mut x_fixed = Array2::zeros((n_obs, 2));
    let mut y = Array1::zeros(n_obs);
    let mut groups = vec![0; n_obs];

    // Create balanced data with known structure
    // True parameters: β0 = 2.0, β1 = 0.5, σ² = 1.0, τ² = 0.5
    let true_intercept = 2.0;
    let true_slope = 0.5;
    let true_sigma2 = 1.0;
    let true_tau2 = 0.5;

    // Random number generation for reproducibility
    use rand::{SeedableRng, Rng};
    use rand::rngs::StdRng;
    use rand_distr::{Normal, Distribution};

    let mut rng = StdRng::seed_from_u64(42);
    let normal_residual = Normal::new(0.0, true_sigma2.sqrt()).unwrap();
