//! Benchmarks comparing mixed_models performance to R's lme4
//!
//! These benchmarks verify we achieve:
//! - ≥2x speed improvement over lme4::lmer
//! - ≤50% memory usage compared to lme4

use criterion::{black_box, criterion_group, criterion_main, BenchmarkId, Criterion};
use mixed_models::{LinearMixedModel, MixedModelSpec, RandomEffectsSpec};
use ndarray::Array2;
use rand::{SeedableRng, Rng};
use rand::rngs::StdRng;
use rand_distr::{Normal, Distribution};
use std::time::Duration;

/// Generate large dataset for benchmarking
/// Returns (X, y, groups) tuple
fn generate_large_dataset(n_obs: usize, n_groups: usize, seed: u64) -> (Array2<f64>, Vec<f64>, Vec<usize>) {
    let mut rng = StdRng::seed_from_u64(seed);
    let normal = Normal::new(0.0, 1.0).unwrap();

    // Fixed effects design matrix (intercept + 3 covariates)
    let mut x = Array2::zeros((n_obs, 4));
    let mut y = vec![0.0; n_obs];
    let mut groups = vec![0; n_obs];

    // True parameters
    let beta = vec![2.0, 0.5, -0.3, 0.2];
    let sigma = 1.0;
    let tau = 0.5;

    // Generate group effects
    let mut group_effects = vec![0.0; n_groups];
    for i in 0..n_groups {
        group_effects[i] = normal.sample(&mut rng) * tau;
    }

    // Generate data
    for i in 0..n_obs {
        // Assign to groups (balanced design)
        groups[i] = i % n_groups;

        // Generate predictors
        x[[i, 0]] = 1.0; // intercept
        for j in 1..4 {
            x[[i, j]] = rng.gen_range(-2.0..2.0);
        }

        // Generate response
        y[i] = beta.iter()
            .zip(0..4)
            .map(|(b, j)| b * x[[i, j]])
            .sum::<f64>()
            + group_effects[groups[i]]
            + normal.sample(&mut rng) * sigma;
    }

    (x, y, groups)
}

/// Benchmark mixed model fitting on various dataset sizes
fn bench_lmer_fit(c: &mut Criterion) {
    let mut group = c.benchmark_group("lmer_fit");
    group.measurement_time(Duration::from_secs(30));
    group.sample_size(10);

    // Test different dataset sizes
    let configs = [
        ("small", 10_000, 100),      // 10K observations, 100 groups
        ("medium", 100_000, 1_000),  // 100K observations, 1K groups
        ("large", 1_000_000, 10_000), // 1M observations, 10K groups (S7-T09/T10 requirement)
    ];

    for (name, n_obs, n_groups) in configs.iter() {
        let (x, y, groups) = generate_large_dataset(*n_obs, *n_groups, 42);

        // Create model specification
        let fixed_effects = formula::ModelSpec::new("y", vec!["1".to_string(), "x1".to_string(), "x2".to_string(), "x3".to_string()]);
        let random_effects = vec![RandomEffectsSpec {
            grouping_factor: "group".to_string(),
            terms: vec!["1".to_string()],
            include_intercept: true,
        }];
        let model_spec = MixedModelSpec { fixed_effects, random_effects };

        group.bench_with_input(
            BenchmarkId::new("mixed_models", name),
            &(x.view(), &y, &groups),
            |b, (x, y, groups)| {
                b.iter(|| {
                    let lmm = LinearMixedModel::new(model_spec.clone());
                    let fit = lmm.fit(*x, ndarray::ArrayView1::from(*y), *groups).unwrap();
                    black_box(fit);
                });
            },
        );
    }

    group.finish();
}

/// Benchmark memory usage for large dataset
/// This is a pseudo-benchmark that measures peak memory allocation
fn bench_memory_usage(c: &mut Criterion) {
    let mut group = c.benchmark_group("lmer_memory");
    group.measurement_time(Duration::from_secs(10));
    group.sample_size(10);

    // Large dataset matching S7-T09 requirements: 1M obs, 10K groups
    let (x, y, groups) = generate_large_dataset(1_000_000, 10_000, 42);

    // Create model specification
    let fixed_effects = formula::ModelSpec::new("y", vec!["1".to_string(), "x1".to_string(), "x2".to_string(), "x3".to_string()]);
    let random_effects = vec![RandomEffectsSpec {
        grouping_factor: "group".to_string(),
        terms: vec!["1".to_string()],
        include_intercept: true,
    }];
    let model_spec = MixedModelSpec { fixed_effects, random_effects };

    group.bench_function("large_dataset", |b| {
        b.iter(|| {
            // Measure memory allocation during fit
            let lmm = LinearMixedModel::new(model_spec.clone());
            let _fit = lmm.fit(x.view(), ndarray::ArrayView1::from(&y), &groups).unwrap();

            // Note: Actual memory measurement would require external tools or custom allocator
            // This benchmark primarily measures time, but memory usage can be monitored
            // using tools like heaptrack or massif when running the benchmark
        });
    });

    group.finish();
}

/// Benchmark comparison with multi-threading enabled
/// Verifies performance gain on multi-core systems
fn bench_parallel_performance(c: &mut Criterion) {
    let mut group = c.benchmark_group("lmer_parallel");
    group.measurement_time(Duration::from_secs(20));

    // Large dataset for parallel performance testing
    let (x, y, groups) = generate_large_dataset(500_000, 5_000, 42);

    // Create model specification  
    let fixed_effects = formula::ModelSpec::new("y", vec!["1".to_string(), "x1".to_string(), "x2".to_string(), "x3".to_string()]);
    let random_effects = vec![RandomEffectsSpec {
        grouping_factor: "group".to_string(),
        terms: vec!["1".to_string()],
        include_intercept: true,
    }];
    let model_spec = MixedModelSpec { fixed_effects, random_effects };

    // Benchmark with parallel enabled (default)
    group.bench_function("parallel_enabled", |b| {
        b.iter(|| {
            let lmm = LinearMixedModel::new(model_spec.clone());
            let fit = lmm.fit(x.view(), ndarray::ArrayView1::from(&y), &groups).unwrap();
            black_box(fit);
        });
    });

    // Benchmark with parallel disabled
    group.bench_function("parallel_disabled", |b| {
        b.iter(|| {
            let mut lmm = LinearMixedModel::new(model_spec.clone());
            lmm.config.parallel = false;
            let fit = lmm.fit(x.view(), ndarray::ArrayView1::from(&y), &groups).unwrap();
            black_box(fit);
        });
    });

    group.finish();
}

/// Memory profiling helper - can be used with external memory profilers
/// Run with: cargo bench --bench lmer_benchmarks -- memory_profile --nocapture
#[allow(dead_code)]
fn memory_profile() {
    println!("Starting memory profile for large dataset...");

    // Generate 1M observations, 10K groups dataset
    let (x, y, groups) = generate_large_dataset(1_000_000, 10_000, 42);

    println!("Dataset generated: {} observations, {} groups", 1_000_000, 10_000);
    println!("Approximate dataset memory: {} MB", 
        (x.len() * 8 + y.len() * 8 + groups.len() * 8) / (1024 * 1024));

    // Create and fit model
    let fixed_effects = formula::ModelSpec::new("y", vec!["1".to_string(), "x1".to_string(), "x2".to_string(), "x3".to_string()]);
    let random_effects = vec![RandomEffectsSpec {
        grouping_factor: "group".to_string(),
        terms: vec!["1".to_string()],
        include_intercept: true,
    }];
    let model_spec = MixedModelSpec { fixed_effects, random_effects };

    println!("Fitting model...");
    let start = std::time::Instant::now();

    let lmm = LinearMixedModel::new(model_spec);
    let fit = lmm.fit(x.view(), ndarray::ArrayView1::from(&y), &groups).unwrap();

    let elapsed = start.elapsed();
    println!("Model fitted in {:?}", elapsed);
    println!("Iterations: {}", fit.iterations);
    println!("Log-likelihood: {}", fit.log_likelihood);

    // Keep fit in scope to prevent deallocation
    std::hint::black_box(fit);

    println!("Memory profile complete. Use external tools to analyze memory usage.");
}

/// Comparison metrics for reporting
/// These would be compared against R lme4 benchmarks run separately
fn print_benchmark_targets() {
    println!("\n=== Mixed Models Performance Targets (vs lme4) ===");
    println!("Dataset: 1M observations, 10K groups");
    println!("Model: y ~ x1 + x2 + x3 + (1|group)");
    println!();
    println!("Performance targets:");
    println!("- Speed: ≥2x faster than lme4::lmer");
    println!("- Memory: ≤50% of lme4 peak memory usage");
    println!();
    println!("Expected lme4 baseline (approximate):");
    println!("- Time: ~30-60 seconds on modern hardware");
    println!("- Memory: ~8-12 GB peak usage");
    println!();
    println!("Our targets:");
    println!("- Time: ≤15-30 seconds");
    println!("- Memory: ≤4-6 GB peak usage");
    println!("===========================================\n");
}

criterion_group!(benches, bench_lmer_fit, bench_memory_usage, bench_parallel_performance);
criterion_main!(benches);

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_benchmark_data_generation() {
        let (x, y, groups) = generate_large_dataset(1000, 10, 42);
        assert_eq!(x.nrows(), 1000);
        assert_eq!(x.ncols(), 4);
        assert_eq!(y.len(), 1000);
        assert_eq!(groups.len(), 1000);

        // Verify groups are balanced
        let mut group_counts = vec![0; 10];
        for &g in &groups {
            group_counts[g] += 1;
        }
        for count in group_counts {
            assert_eq!(count, 100);
        }
    }
}

